'use client';

/**
 * AI Response Renderer - Dark Theme
 * Renders AI-generated responses with markdown support
 */

import ReactMarkdown from 'react-markdown';

interface AIResponseRendererProps {
  content: string;
  className?: string;
}

export function AIResponseRendererDark({ content, className = '' }: AIResponseRendererProps) {
  return (
    <div className={`prose prose-invert prose-sm max-w-none ${className}`}>
      <ReactMarkdown>{content}</ReactMarkdown>
    </div>
  );
}

export function AIResponseRenderer({ content, className = '' }: AIResponseRendererProps) {
  return (
    <div className={`prose prose-sm max-w-none ${className}`}>
      <ReactMarkdown>{content}</ReactMarkdown>
    </div>
  );
}
